VALUES
  ('elementary-10ced7e2-moex-00751', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於民事訴訟上當事人能力之敘述，何者正確？', '["當事人能力為訴訟成立要件之一，若當事人欠缺當事人能力，法院應逕行以訴不合法裁定駁回其訴", "非法人團體因不具權利能力，因此不具有當事人能力", "無當事人能力人所為之訴訟行為，其效力得經取得能力之人承認而治癒", "當事人於訴訟中死亡時，法院應即以當事人能力有欠缺而裁定駁回其訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00752', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於行政罰的敘述，何者錯誤？', '["違反行政法上義務之行為，以處罰故意為原則，過失行為之處罰以法律有明文規定為限", "滿十四歲以上，未滿十八歲人之行為，得減輕處罰", "不得因不知法規而免除行政處罰責任", "違反行政法上義務之行為非出於故意或過失者，不予處罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00753', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列行政訴訟法所定之訴訟種類，何者非以行政處分為程序標的？', '["撤銷訴訟", "申請遭否准之訴訟", "怠為處分訴訟", "一般給付訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00754', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列有關訴願要件之敘述，何者錯誤？', '["除行政處分違法外，行政處分不當亦得提起訴願", "訴願的對象尚包括消極的不作為", "一律以原處分機關為受理訴願機關", "須以權利或法律上利益遭受侵害為前提"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00755', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列事件何者為人民不服時可提起訴願的標的？', '["稅捐稽徵機關對業者實施實地查核之行為", "甲機關聘僱臨時人員所生薪資給付不足之爭議", "丙所有之土地被乙機關徵收而對徵收價格不服之爭議", "丁警員執行勤務不慎駕車撞傷人民戊所生的糾紛"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00756', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲夫乙妻結婚多年，無子女。甲尚有祖父丙、祖母丁。甲死亡時，丁依法辦理拋棄繼承。乙之應繼分為 多少？', '["2/3", "1/2", "1/3", "1/4"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00757', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於民事訴訟上和解，何者錯誤？', '["土地疆界糾紛之訴訟，得成立訴訟上和解", "法院調解成立者，與訴訟上和解有同一之效力", "當事人就未聲明之事項成立和解者，不得為執行名義", "當事人於和解之意思已甚接近，得聲請法院於當事人表明之範圍內，定和解方案，於法院將和解方案 送達兩造時，視為和解成立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00758', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '違反行政法上義務，得予行政處罰之法源依據，下列何者錯誤？', '["財政部函釋", "法律明文授權訂定之法規命令", "法律", "地方自治條例"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00759', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於民事訴訟法上公開審理、言詞審理及直接審理原則之敘述，何者正確？', '["言詞辯論，應由訴訟代理人以言詞聲明當事人與關係人人數，以及相關證據資料為其程序之開始", "當事人應就訴訟關係，為事實上之陳述，其訴訟代理人應就訴訟關係，為法律上之陳述。兩者相異者， 以訴訟代理人之陳述為準", "法官非參與為判決基礎之辯論者，不得參與判決", "原告提出之攻擊或防禦方法，涉及被告之營業秘密者，僅得由法院以職權逕行裁定為審理不公開與判 決不公開"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00760', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列有關訊問刑事被告應告知事項之敘述，何者正確？', '["被告所犯罪名經告知後，如有變更，不必再告知", "被告犯想像競合犯裁判上一罪之案件，只要告知重罪罪名即可", "告知得選任辯護人", "被告得保持緘默，亦得說謊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
